'use client';
import gsap from "gsap";
import { useEffect, useState } from "react";

export const ScrollHint = () => {
  const [showScrollHint, setShowScrollHint] = useState(true);

  useEffect(() => {
    const handleScroll = () => {
      setShowScrollHint(window.scrollY < 100);
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    if (showScrollHint) {
      gsap.to('.scroll-hint', {
        opacity: 1,
        duration: 1.5,
        delay: 1.5,
      });
    } else {
      gsap.killTweensOf('.scroll-hint');
      gsap.to('.scroll-hint', {
        opacity: 0,
        duration: 0.5,
      });
    }
  }, [showScrollHint]);

  return (
    <div className="fixed w-full bottom-5 scroll-hint pointer-events-none" style={{ opacity: 0, zIndex: 10 }}>
      <div className="flex items-center justify-center animate-pulse gap-2">
        {/* @ts-ignore */}
        <ion-icon name="arrow-down-outline" style={{ color: "white" }}></ion-icon>
        <span className="text-white tracking-widest text-sm font-semibold">SCROLL</span>
      </div>
    </div>
  );
}

export default ScrollHint;